final class BiometricAuth {
    private BiometricAuth() {}

    interface Callback {
        void onSuccess();
        void onFailure();
        void onError(int errorCode, @NonNull CharSequence errString);
        void onUnavailable(@NonNull String reason);
    }

    static boolean canAuthenticate(Context context) {
        BiometricManager bm = BiometricManager.from(context);
        int res = bm.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG
                | BiometricManager.Authenticators.BIOMETRIC_WEAK);
        return res == BiometricManager.BIOMETRIC_SUCCESS;
    }

    static String canAuthenticateReason(Context context) {
        BiometricManager bm = BiometricManager.from(context);
        int res = bm.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG
                | BiometricManager.Authenticators.BIOMETRIC_WEAK);
        switch (res) {
            case BiometricManager.BIOMETRIC_SUCCESS:
                return "OK";
            case BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE:
                return "No biometric hardware";
            case BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE:
                return "Biometric hardware unavailable";
            case BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED:
                return "No biometrics enrolled";
            case BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_REQUIRED:
                return "Security update required";
            case BiometricManager.BIOMETRIC_ERROR_UNSUPPORTED:
                return "Biometrics unsupported";
            case BiometricManager.BIOMETRIC_STATUS_UNKNOWN:
            default:
                return "Biometric status unknown";
        }
    }

    static void authenticate(@NonNull AppCompatActivity activity,
                             @NonNull String title,
                             @NonNull String subtitle,
                             @NonNull String negativeButtonText,
                             @NonNull Callback callback) {

        if (!canAuthenticate(activity)) {
            callback.onUnavailable(canAuthenticateReason(activity));
            return;
        }

        Executor executor = ContextCompat.getMainExecutor(activity);

        BiometricPrompt.AuthenticationCallback authCallback = new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                callback.onError(errorCode, errString);
            }

            @Override
            public void onAuthenticationFailed() {
                callback.onFailure();
            }

            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                callback.onSuccess();
            }
        };

        BiometricPrompt prompt = new BiometricPrompt(activity, executor, authCallback);

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle(title)
                .setSubtitle(subtitle)
                .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG
                        | BiometricManager.Authenticators.BIOMETRIC_WEAK)
                .setNegativeButtonText(negativeButtonText)
                .build();

        prompt.authenticate(promptInfo);
    }
}

class LauncherActivity extends AppCompatActivity {
    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (Prefs.isLoggedIn(this)) {
            startActivity(new Intent(this, HomeActivity.class));
            finish();
            return;
        }

        if (Prefs.isBiometricEnabled(this) && BiometricAuth.canAuthenticate(this)) {
            BiometricAuth.authenticate(
                    this,
                    "Unlock",
                    "Use your fingerprint to unlock",
                    "Use password",
                    new BiometricAuth.Callback() {
                        @Override
                        public void onSuccess() {
                            Prefs.setLoggedIn(LauncherActivity.this, true);
                            startActivity(new Intent(LauncherActivity.this, HomeActivity.class));
                            finish();
                        }

                        @Override
                        public void onFailure() {
                        }

                        @Override
                        public void onError(int errorCode, @NonNull CharSequence errString) {
                            startActivity(new Intent(LauncherActivity.this, LoginActivity.class));
                            finish();
                        }

                        @Override
                        public void onUnavailable(@NonNull String reason) {
                            startActivity(new Intent(LauncherActivity.this, LoginActivity.class));
                            finish();
                        }
                    }
            );
        } else {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        }
    }
}

class LoginActivity extends AppCompatActivity {

    private EditText usernameEt;
    private EditText passwordEt;
    private CheckBox enableBiometricCb;
    private TextView statusTv;

    private final ActivityResultLauncher<Intent> enrollLauncher =
            registerForActivityResult(new ActivityResultContracts.StartActivityForResult(), result -> updateBiometricAvailability());

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setPadding(48, 48, 48, 48);
        root.setLayoutParams(new ViewGroup.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.MATCH_PARENT));

        TextView title = new TextView(this);
        title.setText("Login");
        title.setTextSize(22f);

        usernameEt = new EditText(this);
        usernameEt.setHint("Username");

        passwordEt = new EditText(this);
        passwordEt.setHint("Password");
        passwordEt.setInputType(InputType.TYPE_CLASS_TEXT | InputType.TYPE_TEXT_VARIATION_PASSWORD);

        enableBiometricCb = new CheckBox(this);
        enableBiometricCb.setText("Enable biometric login");
        enableBiometricCb.setChecked(Prefs.isBiometricEnabled(this));

        statusTv = new TextView(this);
        statusTv.setTextSize(14f);

        Button loginBtn = new Button(this);
        loginBtn.setText("Login");

        Button biometricBtn = new Button(this);
        biometricBtn.setText("Unlock with fingerprint");

        Button enrollBtn = new Button(this);
        enrollBtn.setText("Enroll biometrics");

        root.addView(title);
        root.addView(usernameEt);
        root.addView(passwordEt);
        root.addView(enableBiometricCb);
        root.addView(loginBtn);
        root.addView(biometricBtn);
        root.addView(enrollBtn);
        root.addView(statusTv);

        setContentView(root);

        updateBiometricAvailability();

        enableBiometricCb.setOnCheckedChangeListener((buttonView, isChecked) -> {
            if (isChecked) {
                if (!BiometricAuth.canAuthenticate(this)) {
                    enableBiometricCb.setChecked(false);
                    statusTv.setText("Biometric unavailable: " + BiometricAuth.canAuthenticateReason(this));
                    return;
                }
                BiometricAuth.authenticate(
                        this,
                        "Enable biometric login",
                        "Confirm your fingerprint to enable",
                        "Cancel",
                        new BiometricAuth.Callback() {
                            @Override
                            public void onSuccess() {
                                Prefs.setBiometricEnabled(LoginActivity.this, true);
                                statusTv.setText("Biometric login enabled");
                            }

                            @Override
                            public void onFailure() {
                            }

                            @Override
                            public void onError(int errorCode, @NonNull CharSequence errString) {
                                enableBiometricCb.setChecked(false);
                                Prefs.setBiometricEnabled(LoginActivity.this, false);
                                statusTv.setText("Cancelled");
                            }

                            @Override
                            public void onUnavailable(@NonNull String reason) {
                                enableBiometricCb.setChecked(false);
                                Prefs.setBiometricEnabled(LoginActivity.this, false);
                                statusTv.setText("Biometric unavailable: " + reason);
                            }
                        }
                );
            } else {
                Prefs.setBiometricEnabled(this, false);
                statusTv.setText("Biometric login disabled");
            }
        });

        loginBtn.setOnClickListener(v -> {
            String u = usernameEt.getText() == null ? "" : usernameEt.getText().toString().trim();
            String p = passwordEt.getText() == null ? "" : passwordEt.getText().toString();

            if (u.isEmpty() || p.isEmpty()) {
                statusTv.setText("Enter username and password");
                return;
            }

            Prefs.setLoggedIn(this, true);

            if (enableBiometricCb.isChecked()) {
                Prefs.setBiometricEnabled(this, true);
            }

            startActivity(new Intent(this, HomeActivity.class));
            finish();
        });

        biometricBtn.setOnClickListener(v -> {
            if (!Prefs.isBiometricEnabled(this)) {
                statusTv.setText("Enable biometric login first");
                return;
            }
            BiometricAuth.authenticate(
                    this,
                    "Unlock",
                    "Use your fingerprint to unlock",
                    "Use password",
                    new BiometricAuth.Callback() {
                        @Override
                        public void onSuccess() {
                            Prefs.setLoggedIn(LoginActivity.this, true);
                            startActivity(new Intent(LoginActivity.this, HomeActivity.class));
                            finish();
                        }

                        @Override
                        public void onFailure() {
                            statusTv.setText("Not recognized. Try again.");
                        }

                        @Override
                        public void onError(int errorCode, @NonNull CharSequence errString) {
                            statusTv.setText(errString);
                        }

                        @Override
                        public void onUnavailable(@NonNull String reason) {
                            statusTv.setText("Biometric unavailable: " + reason);
                        }
                    }
            );
        });

        enrollBtn.setOnClickListener(v -> {
            Intent intent = new Intent(android.provider.Settings.ACTION_BIOMETRIC_ENROLL);
            intent.putExtra(android.provider.Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED,
                    BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.BIOMETRIC_WEAK);
            try {
                enrollLauncher.launch(intent);
            } catch (Exception e) {
                statusTv.setText("Cannot open enroll settings");
            }
        });
    }

    private void updateBiometricAvailability() {
        boolean can = BiometricAuth.canAuthenticate(this);
        String reason = BiometricAuth.canAuthenticateReason(this);

        if (!can) {
            statusTv.setText("Biometric unavailable: " + reason);
        } else {
            statusTv.setText("Biometric available");
        }
    }
}

class HomeActivity extends AppCompatActivity {

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setGravity(Gravity.CENTER_HORIZONTAL);
        root.setPadding(48, 48, 48, 48);

        TextView tv = new TextView(this);
        tv.setTextSize(20f);
        tv.setText("Home");

        Button logoutBtn = new Button(this);
        logoutBtn.setText("Logout");

        Button lockBtn = new Button(this);
        lockBtn.setText("Lock app");

        root.addView(tv);
        root.addView(logoutBtn);
        root.addView(lockBtn);

        setContentView(root);

        logoutBtn.setOnClickListener(v -> {
            Prefs.logout(this);
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        });

        lockBtn.setOnClickListener(v -> {
            Prefs.setLoggedIn(this, false);
            startActivity(new Intent(this, LauncherActivity.class));
            finish();
        });
    }
}